1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: string; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = ["rune", "moonstone"];
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PRICE = 60;
20	
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const LOYALTY_MIN_YEARS = 2;
27	
28	const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
29	
30	const isCursed = (item: Item): boolean => item.cursed === true;
31	
32	const isHighlyEnchanted = (item: Item): boolean =>
33	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
34	
35	const itemSurchargeRate = (item: Item): number =>
36	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
37	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
38	
39	const premiumForItem = (item: Item): number =>
40	  baseForType(item.type) * (1 + itemSurchargeRate(item));
41	
42	const countItemsOfType = (items: Item[], type: string): number =>
43	  items.filter((item) => item.type === type).length;
44	
45	const premiumForComponentType = (items: Item[], type: string): number => {
46	  const count = countItemsOfType(items, type);
47	  return count === COMPONENT_BLOCK_SIZE
48	    ? COMPONENT_BLOCK_PRICE
49	    : count * baseForType(type);
50	};
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
53	
54	const basePremiumFor = (items: Item[]): number => {
55	  const componentsTotal = COMPONENT_TYPES.reduce(
56	    (sum, type) => sum + premiumForComponentType(items, type),
57	    0,
58	  );
59	  const nonComponentsTotal = items
60	    .filter((item) => !isComponent(item))
61	    .reduce((sum, item) => sum + premiumForItem(item), 0);
62	  return componentsTotal + nonComponentsTotal;
63	};
64	
65	const loyaltyMultiplier = (customer: Customer): number =>
66	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? 1 - LOYALTY_DISCOUNT_RATE : 1;
67	
68	const policyMultiplier = (customer: Customer): number => loyaltyMultiplier(customer);
69	
70	const quotePremium = (items: Item[], customer: Customer): number =>
71	  basePremiumFor(items) * policyMultiplier(customer) + PROCESSING_FEE;
72	
73	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
74	  const { customer, steps } = input as Scenario;
75	  return { results: [{ premium: quotePremium(steps[0].items, customer) }] };
76	};
